              transition={{
                bounce: 0,
                duration: 0.4,
                type: "spring",
              }}
              className="flex w-full items-center justify-between"
            >
              <span className="text-xl font-bold tracking-wide text-zinc-500 dark:text-zinc-400">
                {code}
              </span>

              <motion.button
                onClick={handleCopy}
                whileHover={{ scale: 1.04, y: -1 }}
