                  whileHover={{ x: "120%" }}
                  transition={{ duration: 0.6, ease: "easeInOut" }}
                  className="pointer-events-none absolute inset-0 bg-linear-to-r from-transparent via-black/5 to-transparent"
                />

                <span className="relative z-10">Copy</span>
              </motion.button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

